package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetCommentMarker() throws Exception {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, '#', '\\', true, false, "\r\n",
                "\\N", new Object[]{}, new String[]{}, false, true, false, true, false);

        // Using reflection to access and set the private field
        java.lang.reflect.Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        commentMarkerField.set(csvFormat, '#');

        // When
        Character result = csvFormat.getCommentMarker();

        // Then
        assertEquals('#', result);
    }
}
